class Solution {
    public boolean isPossible(int[] nums) {
        int n = nums.length;
        int[] count = new int[1001];
        int[] used = new int[1001];

        for (int num : nums) {
            count[num]++;
        }

        for (int num = 0; num <= 1000; num++) {
            if (count[num] > 0) {
                if (count[num] <= used[num]) {
                    continue;
                }

                int remaining = count[num] - used[num];
                if (count[num + 1] >= remaining && count[num + 2] >= remaining) {
                    count[num + 1] -= remaining;
                    count[num + 2] -= remaining;
                    used[num + 3] += remaining;
                } else {
                    return false;
                }
            }
        }

        return true;
    }
}
